const vt_malicious = $node["VirusTotal"].json.data?.attributes?.last_analysis_stats?.malicious ?? 0;
const vt_suspicious = $node["VirusTotal"].json.data?.attributes?.last_analysis_stats?.suspicious ?? 0;
const abuse_score = $node["AbuseIPDB"].json.data?.abuseConfidenceScore ?? 0;
const otx_pulses = $node["OTX AlienVault"].json.pulse_info?.count ?? 0;
const severity = parseInt($('IF Severity >= 5').item.json.severity) || 0;
const intermediate_score = Math.min(100, (vt_malicious * 4) + (vt_suspicious * 1) + (abuse_score * 0.4) + (otx_pulses * 2) + (severity * 4));
return { ...item.json, intermediate_score };

const score = item.json.risk_score ?? 0;
const risk_level = score >= 75 ? 'CRITICAL' : score >= 50 ? 'HIGH' : score >= 25 ? 'MEDIUM' : 'LOW';
const action = score >= 75 ? 'IMMEDIATE_RESPONSE' : score >= 50 ? 'INVESTIGATE' : score >= 25 ? 'MONITOR' : 'LOG_ONLY';
return { ...item.json, risk_level, action };

