const items = $input.all();
if (!items || items.length === 0) {
  return [{ json: { data: [] } }];
}
const data = items[0]?.json?.data;
if (!data || !Array.isArray(data) || data.length === 0) {
  return [{ json: { data: [] } }];
}
if (data[0]?.query_type) {
  return [{ json: { data: data } }];
}
if (data[0]?.error) {
  return [{ json: { data: data } }];
}
const firstRow = data[0];
const keys = Object.keys(firstRow);
if (!keys.includes('alert_name')) {
  return [{ json: { data: data } }];
}
const groups = {};
for (const row of data) {
  const key = `${row.ip || ''}|${row.alert_name || ''}|${row.risk_level || ''}`;
  if (!groups[key]) {
    groups[key] = {
      ip: row.ip || 'Unknown',
      alert_name: row.alert_name || 'Unknown Alert',
      risk_level: row.risk_level || 'LOW',
      mitre_attack: row.mitre_attack || 'N/A',
      country: row.country || 'Unknown',
      highest_score: row.risk_score || 0,
      hit_count: 1,
      agent_name: row.agent_name || 'Unknown',
      rule_id: row.rule_id || 'N/A',
      shodan_vulns: row.shodan_vulns || 'N/A',
      vt_score: row.vt_score || 0,
      abuse_score: row.abuse_score || 0,
      shodan_ports: row.shodan_ports || 'N/A'
    };
  } else {
    groups[key].hit_count++;
    if ((row.risk_score || 0) > groups[key].highest_score) {
      groups[key].highest_score = row.risk_score;
    }
  }
}
const riskOrder = { 'CRITICAL': 4, 'HIGH': 3, 'MEDIUM': 2, 'LOW': 1 };
const deduplicated = Object.values(groups).sort((a, b) => {
  const riskDiff = (riskOrder[b.risk_level] || 0) - (riskOrder[a.risk_level] || 0);
  if (riskDiff !== 0) return riskDiff;
  return b.hit_count - a.hit_count;
});
return [{ json: { data: deduplicated } }];

